var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"다행히 건물이 무너지던 와중에도 이곳은 무사하군.","JPN":"建物は崩壊しているが、幸いここだけは無事のようだ。","ENG":"Luckily, this place seems safe given the building is crumbling.","TWN":"幸好建築物雖然倒塌，但這裡沒有遭殃。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"갑자기 뛰어가시면 어떡해요?! 그러다가 건물이 또 무너지면 어떡하시려고!","JPN":"急に走り出してどうしたんですか！？　また建物が崩れたりしたら大変なんですよ！","ENG":"Where are you suddenly running off to?! What if the building starts to come down again?!","TWN":"你怎麼可以突然跑走？！萬一建築物又倒塌的話怎麼辦！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"은폐장은 물론이고, 모든 보안 장치가 파괴되었어.","JPN":"隠蔽バリアをはじめとする、あらゆるセキュリティ装置が破損している。","ENG":"The cloaking barrier and all security devices have been destroyed.","TWN":"不只是藏身之處，連所有的安全設備也都遭到破壞。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"정말…… 이렇게 많은 시간이 흘렀다고?","JPN":"本当に……それだけの時間が流れたというのか？","ENG":"Has... it really been that long?","TWN":"我真的……有沉睡這麼長的時間嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이렇게 모든 배관이 캡슐을 향해 이어져 있었어요.","JPN":"ここにあるすべてのパイプがカプセルに繋がっていました。","ENG":"All the pipes were connected to the capsule like this.","TWN":"所有的管線都通向膠囊，"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 배관을 따라갔더니 당신이 잠들어 있었죠.","JPN":"パイプを辿っていくと、そこにはあなたが眠っていたんです。","ENG":"I was following them when I found you asleep.","TWN":"我沿著那些管線走，就看見你在沉睡。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"떠오르는 게 있으신가요?","JPN":"何か思い出しましたか？","ENG":"Is there anything that you do remember?","TWN":"你有想起什麼嗎？ "},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"전혀. 내가 착각하고 있는 것은 아닐지 걱정될 정도로.","JPN":"まったくだ。私が錯覚しているのではないかと心配になるくらいにな。","ENG":"Nothing. Enough so that I'm worried I might be mistaken.","TWN":"完全沒有，我甚至擔心是不是自己搞錯什麼。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"아니, 차라리 그랬으면 좋겠군.","JPN":"むしろ、その方がいいのかもしれないが。","ENG":"No, it would be better if I was.","TWN":"不，應該說，我寧願是我哪裡搞錯。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"내가 아주 잘 만들어진 복제 인간이라서 원본과 나를 혼동한다는 착각.","JPN":"私は精巧に作られた複製人間であり、本体と自分の区別がつかなくなっている……とか。","ENG":"Thinking that I'm a well-made clone who is getting confused with the original.","TWN":"我希望我其實是一個完美複製人，所以才會把我和本尊搞錯。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"그 나침반을 잠깐 봐도 되겠나?","JPN":"その羅針盤を見せてもらえるか？","ENG":"That compass, may I see it?","TWN":"那個指南針可以借我看一下嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여기요.","JPN":"はい、どうぞ。","ENG":"Here you go.","TWN":"給你。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…… 내가 움직이는 방향을 따라오는군.","JPN":"……針が私を追ってくる。","ENG":"...It's following the direction I'm moving to.","TWN":"…… 針跟著我移動呢。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여러 곳을 떠돌아다니면서도 이상하게도 잃어버리지 않았던 물건이에요.","JPN":"色んな場所を放浪してきましたが、これだけは決して無くしませんでした。","ENG":"Strangely enough, this is the one thing that I haven't lost while wandering around everywhere.","TWN":"而且很奇怪，我去過這麼多地方，卻從來沒有弄丟過它。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"언제부터 가지고 있었는지도 잘 모르겠어요. 하지만 항상 제 곁에 있었죠.","JPN":"いつからあったのかもわかりませんが、常に私の手元にあったんです。","ENG":"I'm not sure how long I've had it. But it's been with me ever since.","TWN":"也記不清是從什麼時候開始帶在身上的，總之它就是跟我形影不離。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바늘이 당신을 향한다는 건 여기 와서 안 사실이지만…….","JPN":"針が示していたのがあなただったとは、ここに来て知りましたが……","ENG":"I only learned that it points to you after coming here, however...","TWN":"不過針指向你，是我到這裡後才發現的……"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"나를 향하는 나침반이라…….","JPN":"私を示す羅針盤か……","ENG":"A compass that points to me...","TWN":"指向我的指南針……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이건 여러분들 모두에게 지급되는 장비인 나침반입니다.","JPN":"この羅針盤は、皆さん一人一人に支給されます。","ENG":"This is a compass that will be issued to all of you.","TWN":"這是指南針，是要會發給各位的裝備。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"바늘은 같은 나침반을 향해 움직이죠.","JPN":"針は同じ羅針盤同士を指し示します。","ENG":"The needle inside will point toward another compass.","TWN":"上面的針會朝著相同的指南針移動。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이 나침반은 서로의 위치를 더 잘 알게 하기 위함으로…….","JPN":"この羅針盤はお互いの位置を把握するのに役立ち……","ENG":"This equipment will be used to better know each other's locations...","TWN":"這個指南針用意在清楚彼此的位置……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"……나침반.","JPN":"……羅針盤。","ENG":"...The compass.","TWN":"……指南針。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};